<span class="line"><span style="color:#CDD6F4;">subtasks </span><span style="color:#94E2D5;">=</span><span style="color:#89B4FA;"> decompose</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">task</span><span style="color:#9399B2;">)</span></span>
