<span class="line"><span style="color:#CBA6F7;">for</span><span style="color:#CDD6F4;"> subtask </span><span style="color:#CBA6F7;">in</span><span style="color:#CDD6F4;"> subtasks</span><span style="color:#9399B2;">:</span></span>
